param([string]$Root="C:\ENGREMIAT_CORE")
$ErrorActionPreference="Stop"
[Console]::OutputEncoding=[System.Text.UTF8Encoding]::new()
function L([string]$m,[string]$c="Gray"){Write-Host $m -ForegroundColor $c}
function LastReport([string]$Dir){if(!(Test-Path $Dir)){return ""};$f=@(Get-ChildItem $Dir -File -ErrorAction SilentlyContinue|Sort-Object LastWriteTime -Descending|Select-Object -First 1);if($f.Count -gt 0){return $f[0].FullName};return ""}
while($true){Clear-Host;$launcher=Join-Path $Root "tools\desktop-terminal-operator\Start-EngremiatDesktopOperator.ps1";$lab=Join-Path $Root "reports\system-simulation-lab";L "ENGREMIAT STATUS" Cyan;L ("workspace="+$Root) Gray;L ("desktop_launcher_exists="+[string](Test-Path -LiteralPath $launcher)) Green;L ("simulation_lab_exists="+[string](Test-Path -LiteralPath $lab)) Green;L ("last_operator_report="+(LastReport (Join-Path $Root "reports\desktop-terminal-operator"))) Gray;L ("last_simulation_lab_report="+(LastReport (Join-Path $Root "reports\system-simulation-lab"))) Gray;L "next=E04_COMMAND_ROUTER" Magenta;L "";L " [b] Atras" Yellow;L "";L "refrescar/f5/Enter = redibujar pantalla | b/atras = volver" DarkGray;L "";$choice=(Read-Host "ENGREMIAT").Trim().ToLowerInvariant();if([string]::IsNullOrWhiteSpace($choice) -or $choice -in @("refrescar","refresh","f5","menu","comandos")){continue};if($choice -in @("b","a","atras","atrás","back","volver","0")){exit}}
